import { bigint, boolean, date, integer, jsonb, numeric, pgTable, text, timestamp, uuid, varchar } from "drizzle-orm/pg-core";
export const reportingJobsTable = pgTable("reporting_jobs", {
    id: uuid("id").primaryKey(),
    jobName: varchar("job_name"),
    jobType: varchar("job_type"),
    sourceDatabase: varchar("source_database"),
    sourceTable: varchar("source_table"),
    destinationTable: varchar("destination_table"),
    scheduleType: varchar("schedule_type"),
    status: varchar("status"),
    lastRunAt: timestamp("last_run_at"),
    nextRunAt: timestamp("next_run_at"),
    recordsProcessed: bigint("records_processed", { mode: "number" }),
    recordsFailed: bigint("records_failed", { mode: "number" }),
    errorMessage: text("error_message"),
    createdAt: timestamp("created_at"),
});
export const reportingSnapshotsTable = pgTable("reporting_snapshots", {
    id: uuid("id").primaryKey(),
    snapshotType: varchar("snapshot_type"),
    snapshotDate: date("snapshot_date"),
    snapshotPeriod: varchar("snapshot_period"),
    companyId: uuid("company_id"),
    warehouseId: uuid("warehouse_id"),
    generatedByJobId: uuid("generated_by_job_id").references(() => reportingJobsTable.id),
    status: varchar("status"),
    createdAt: timestamp("created_at"),
});
